{
  "name": "BrewPulse - Smart Coffee System",
  "description": "A sophisticated coffee ordering application with dedicated guest and admin portals, featuring real-time order tracking and AI-powered barista recommendations.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  GUEST = 'GUEST',
  ADMIN = 'ADMIN',
  NONE = 'NONE'
}

export enum CoffeeSize {
  SMALL = 'Small',
  MEDIUM = 'Medium',
  LARGE = 'Large'
}

export type CoffeeType = 'Latte Macchiato' | 'Americano' | 'Espresso' | 'Caramel Macchiato';

export interface Order {
  id: string;
  guestName: string;
  coffeeType: CoffeeType;
  size: CoffeeSize;
  percentage: number;
  timestamp: number;
  status: 'PENDING' | 'PREPARING' | 'COMPLETED';
}

export interface CoffeeOption {
  id: CoffeeType;
  name: string;
  description: string;
  image: string;
}

import React from 'react';
import { CoffeeOption, CoffeeSize } from './types';

