                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <style>{`
        @keyframes bounce-in {
          0% { transform: translateX(100%); opacity: 0; }
          60% { transform: translateX(-5%); opacity: 1; }
