        alert("Erişim Reddedildi: Veritabanı yazma izni yok. Lütfen yönetici ile iletişime geçin veya veritabanı kurallarını kontrol edin.");
      } else {
        alert("Sipariş verilirken bir hata oluştu. Lütfen tekrar deneyin.");
      }
    }
  };

  const handleUpdateStatus = async (id: string, status: Order['status']) => {
    try {
      const orderRef = ref(db, `orders/${id}`);
      await update(orderRef, { status });
    } catch (error) {
      console.error("Update error:", error);
    }
  };

  const handleClearOrder = async (id: string) => {
    try {
      const orderRef = ref(db, `orders/${id}`);
      await remove(orderRef);
    } catch (error) {
      console.error("Delete error:", error);
    }
  };

  const handleLogout = () => {
    setRole(UserRole.NONE);
  };

  if (role === UserRole.NONE) {
    return <Login onSelectRole={setRole} />;
  }

  return (
    <Layout role={role} onLogout={handleLogout}>
      {role === UserRole.GUEST ? (
        <GuestDashboard onPlaceOrder={handlePlaceOrder} />
      ) : (
        <AdminDashboard 
          orders={orders} 
          onUpdateStatus={handleUpdateStatus} 
          onClearOrder={handleClearOrder} 
        />
      )}
    </Layout>
  );
};

export default App;

