import React, { useState, useEffect } from 'react';
import { UserRole, Order } from './types';
import Login from './components/Login';
import Layout from './components/Layout';
import GuestDashboard from './components/GuestDashboard';
import AdminDashboard from './components/AdminDashboard';
import { db, auth } from './services/firebase';
import { 
  ref, 
  onValue, 
  push, 
  update, 
  remove,
  set
} from 'firebase/database';
import { onAuthStateChanged, signOut } from 'firebase/auth';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.NONE);
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [dbError, setDbError] = useState<string | null>(null);
  const [permissionError, setPermissionError] = useState(false);
  const [isServiceOnline, setIsServiceOnline] = useState(true); // Varsayılan açık

  // Auth durumunu ve Oturum Süresini (2 Gün) dinle
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      if (user) {
        // Oturum süresi kontrolü (2 Gün = 48 saat)
        const loginTimeStr = localStorage.getItem('evCoffeeLoginTime');
        const storedRole = localStorage.getItem('evCoffeeRole');

        // Eğer yönetici ise ve süre dolmuşsa at
        if (storedRole === UserRole.ADMIN && loginTimeStr) {
          const loginTime = parseInt(loginTimeStr, 10);
          const twoDaysInMs = 48 * 60 * 60 * 1000;
          const now = Date.now();

          if (now - loginTime > twoDaysInMs) {
            // Süre dolmuş
            handleLogout();
            setLoading(false);
            return;
          }
        }

        if (storedRole === UserRole.ADMIN) {
          setRole(UserRole.ADMIN);
        } else {
          setRole(UserRole.GUEST);
        }
      } else {
        setRole(UserRole.NONE);
        localStorage.removeItem('evCoffeeRole');
        localStorage.removeItem('evCoffeeLoginTime');
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  // Firebase Realtime Database'den verileri ve sistem durumunu dinle
  useEffect(() => {
    if (role === UserRole.NONE) {
      setOrders([]);
      return;
    }

    // 1. Siparişleri Dinle
    const ordersRef = ref(db, 'orders');
    const unsubscribeOrders = onValue(ordersRef, (snapshot) => {
      setDbError(null); 
      setPermissionError(false);
      const data = snapshot.val();
      if (data) {
        const ordersArray = Object.entries(data).map(([key, value]) => {
          return {
            id: key,
            ...(value as Omit<Order, 'id'>)
          };
        });
        setOrders(ordersArray.sort((a, b) => b.timestamp - a.timestamp));
      } else {
        setOrders([]);
      }
    }, (error) => {
      console.error("Veri okuma hatası:", error);
      if (error.code === 'PERMISSION_DENIED' || error.message.includes('permission_denied')) {
        setPermissionError(true);
        setDbError("Erişim Reddedildi: Veritabanı kuralları (Rules) yapılandırılmamış.");
      } else {
        setDbError(`Bağlantı Hatası: ${error.message}. Lütfen services/firebase.ts dosyasındaki databaseURL ayarını kontrol edin.`);
      }
    });

    // 2. Sistem Durumunu (Servis Açık/Kapalı) Dinle
    const systemRef = ref(db, 'system/isOnline');
    const unsubscribeSystem = onValue(systemRef, (snapshot) => {
      const val = snapshot.val();
      // Eğer veritabanında kayıt yoksa varsayılan true kabul et
      setIsServiceOnline(val === null ? true : val);
    });

    return () => {
      unsubscribeOrders();
      unsubscribeSystem();
    };
  }, [role]);

  const handlePlaceOrder = async (orderData: Omit<Order, 'id' | 'timestamp' | 'status'>) => {
    try {
      if (!isServiceOnline) {
        throw new Error("Servis şu anda kapalıdır.");
      }

      const ordersRef = ref(db, 'orders');
      const newOrderRef = push(ordersRef);

      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error("Zaman Aşımı")), 10000)
      );

      const savePromise = set(newOrderRef, {
        ...orderData,
        timestamp: Date.now(),
        status: 'PENDING'
      });

      await Promise.race([savePromise, timeoutPromise]);

      return newOrderRef.key; 
    } catch (error: any) {
      console.error("Sipariş hatası:", error);

      let errorMessage = "Sipariş gönderilemedi.";
      if (error.code === 'PERMISSION_DENIED' || error.message.includes('permission_denied')) {
        setPermissionError(true);
        errorMessage = "Yetki Hatası: Veritabanı kuralları yazmaya izin vermiyor.";
      } else if (error.message === "Zaman Aşımı") {
        errorMessage = "Veritabanına ulaşılamadı. İnternet bağlantınızı kontrol edin.";
      } else {
        errorMessage += " " + error.message;
      }

      if (!permissionError && error.code !== 'PERMISSION_DENIED' && !error.message.includes('permission_denied')) {
          alert(errorMessage);
      }
      throw error;
    }
  };

  const handleUpdateStatus = async (id: string, status: Order['status']) => {
    try {
      const orderRef = ref(db, `orders/${id}`);
      await update(orderRef, { status });
    } catch (error: any) {
      console.error("Güncelleme hatası:", error);
      if (error.code === 'PERMISSION_DENIED' || error.message.includes('permission_denied')) {
         setPermissionError(true);
      } else {
         alert("Durum güncellenemedi: " + error.message);
      }
    }
  };

  const handleClearOrder = async (id: string) => {
    try {
      const orderRef = ref(db, `orders/${id}`);
      await remove(orderRef);
    } catch (error: any) {
      console.error("Silme hatası:", error);
      if (error.code === 'PERMISSION_DENIED' || error.message.includes('permission_denied')) {
         setPermissionError(true);
      }
    }
  };

  const handleToggleService = async (newStatus: boolean) => {
    try {
      await set(ref(db, 'system/isOnline'), newStatus);
    } catch (error: any) {
      alert("Durum değiştirilemedi: " + error.message);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('evCoffeeRole');
    localStorage.removeItem('evCoffeeLoginTime');
    signOut(auth).catch(err => console.error("Çıkış hatası:", err));
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#fcfaf7]">
        <div className="animate-pulse text-stone-400 font-serif">Yükleniyor...</div>
      </div>
    );
  }

  // Permission Error Modal
  if (permissionError) {
    return (
      <div className="fixed inset-0 z-[100] bg-stone-900/90 backdrop-blur-sm flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 max-w-2xl w-full shadow-2xl border-4 border-red-100">
          <div className="flex items-start gap-6">
            <div className="w-16 h-16 bg-red-50 rounded-2xl flex items-center justify-center shrink-0">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
               </svg>
            </div>
            <div className="space-y-4">
              <h2 className="text-2xl font-serif text-stone-900">Veritabanı Kuralları Eksik</h2>
              <p className="text-stone-600">
                Uygulama veritabanına bağlandı ancak <strong>yazma/okuma izni alamadı</strong>. <br/>
                Bu hatayı düzeltmek için Firebase Konsolu'nda şu adımları izleyin:
              </p>

              <ol className="list-decimal list-inside text-sm text-stone-600 space-y-1 ml-1">
                <li>Firebase Konsolu &gt; <strong>Realtime Database</strong> sekmesine gidin.</li>
                <li>Yukarıdaki <strong>Rules (Kurallar)</strong> sekmesine tıklayın.</li>
                <li>Mevcut kodları silin ve aşağıdakini yapıştırın:</li>
              </ol>

              <div className="bg-stone-900 rounded-xl p-4 relative group text-left">
                <code className="text-green-400 font-mono text-sm whitespace-pre block">
{`{
  "rules": {
    ".read": "auth != null",
    ".write": "auth != null"
  }
}`}
                </code>
              </div>

              <div className="bg-orange-50 p-4 rounded-xl border border-orange-100">
                <p className="text-orange-800 text-xs font-bold">
                  İPUCU: "Publish" (Yayınla) butonuna basmayı unutmayın.
                </p>
              </div>

              <button 
                onClick={() => window.location.reload()}
                className="w-full py-4 bg-stone-800 hover:bg-stone-900 text-white rounded-xl font-bold transition-all mt-2"
              >
                Kuralları Güncelledim, Yeniden Dene
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (role === UserRole.NONE) {
    return <Login />;
  }

  return (
    <Layout role={role} onLogout={handleLogout}>
      {dbError && role === UserRole.ADMIN && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-2xl text-red-700 text-sm font-bold flex items-center gap-3">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
           {dbError}
        </div>
      )}

      {role === UserRole.GUEST ? (
        <GuestDashboard 
          orders={orders} 
          onPlaceOrder={handlePlaceOrder} 
          isServiceOnline={isServiceOnline}
        />
      ) : (
        <AdminDashboard 
          orders={orders} 
          onUpdateStatus={handleUpdateStatus} 
          onClearOrder={handleClearOrder}
          isServiceOnline={isServiceOnline}
          onToggleService={handleToggleService}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { auth } from '../services/firebase';
import { signInAnonymously } from 'firebase/auth';
import { UserRole } from '../types';

const Login: React.FC = () => {
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [password, setPassword] = useState('');

  const handleLogin = async (targetRole: UserRole) => {
    setLoading(true);
    setError(null);

    // Role ve Zamanı Kaydet
    localStorage.setItem('evCoffeeRole', targetRole);
    // Yönetici ise giriş zamanını kaydet (2 gün kontrolü için)
    if (targetRole === UserRole.ADMIN) {
        localStorage.setItem('evCoffeeLoginTime', Date.now().toString());
    }

    try {
      await signInAnonymously(auth);
    } catch (err: any) {
      console.error("Giriş hatası:", err);
      // Hata durumunda storage'ı temizle
      localStorage.removeItem('evCoffeeRole');
      localStorage.removeItem('evCoffeeLoginTime');

      if (err.code === 'auth/configuration-not-found') {
        setError("Firebase Konsolunda 'Anonymous' oturum açma yöntemi etkinleştirilmemiş.");
      } else {
        setError("Giriş yapılamadı: " + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleAdminClick = () => {
      setShowPassword(true);
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (password === '2908') {
          handleLogin(UserRole.ADMIN);
      } else {
          setError("Hatalı Şifre");
          setPassword('');
      }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-[#fcfaf7]">
      <div className="max-w-md w-full">
        <div className="text-center mb-16">
          <div className="w-20 h-20 bg-stone-800 rounded-2xl flex items-center justify-center text-white font-bold text-4xl mx-auto shadow-2xl mb-8 italic">E</div>
          <h1 className="text-5xl font-serif text-stone-800 mb-3 tracking-tighter">Ev Coffee</h1>
          <p className="text-stone-400 font-medium italic text-sm">Evinizdeki kahve ritüeli.</p>
        </div>

        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-xs font-bold">
            {error}
          </div>
        )}

        <div className="space-y-5">
          {!showPassword ? (
              <>
                {/* Misafir Girişi Butonu */}
                <button 
                    onClick={() => handleLogin(UserRole.GUEST)}
                    disabled={loading}
                    className="w-full p-8 bg-white border border-stone-100 rounded-3xl shadow-sm hover:shadow-2xl hover:translate-y-[-4px] transition-all text-left group relative overflow-hidden disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    <div className="relative z-10 flex items-center justify-between">
                    <div>
                        <h2 className="text-2xl font-serif text-stone-800">Misafir Girişi</h2>
                        <p className="text-xs text-stone-400 mt-2 font-bold uppercase tracking-widest">
                        {loading ? 'Giriş Yapılıyor...' : 'Kahveni Sipariş Et'}
                        </p>
                    </div>
                    <div className="w-12 h-12 rounded-2xl bg-stone-50 flex items-center justify-center text-stone-800 group-hover:bg-stone-800 group-hover:text-white transition-all duration-500">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
                        </svg>
                    </div>
                    </div>
                </button>

                {/* Barista Girişi Butonu (Şifre Ekranını Açar) */}
                <button 
                    onClick={handleAdminClick}
                    disabled={loading}
                    className="w-full p-8 bg-stone-800 border border-stone-700 rounded-3xl shadow-lg hover:shadow-2xl hover:translate-y-[-4px] transition-all text-left group text-white disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    <div className="flex items-center justify-between">
                    <div>
                        <h2 className="text-2xl font-serif">Barista Paneli</h2>
                        <p className="text-xs text-stone-500 mt-2 font-bold uppercase tracking-widest">
                        {loading ? 'Giriş Yapılıyor...' : 'Yönetici Girişi'}
                        </p>
                    </div>
                    <div className="w-12 h-12 rounded-2xl bg-stone-700 flex items-center justify-center text-stone-400 group-hover:bg-white group-hover:text-stone-800 transition-all duration-500">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                        </svg>
                    </div>
                    </div>
                </button>
            </>
          ) : (
              <form onSubmit={handlePasswordSubmit} className="bg-white p-8 rounded-3xl shadow-xl border border-stone-100 animate-fade-in">
                  <div className="flex justify-between items-center mb-6">
                    <h2 className="text-xl font-serif text-stone-800">Şifre Giriniz</h2>
                    <button type="button" onClick={() => setShowPassword(false)} className="text-stone-400 hover:text-stone-800">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                        </svg>
                    </button>
                  </div>
                  <input 
                    type="password" 
                    autoFocus
                    placeholder="****"
                    className="w-full text-center text-3xl tracking-[1em] py-4 border-b-2 border-stone-200 focus:border-stone-800 outline-none mb-6 font-serif"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    maxLength={4}
                  />
                  <button 
                    type="submit" 
                    className="w-full py-4 bg-stone-800 text-white rounded-xl font-bold uppercase tracking-widest hover:bg-stone-900 transition-all"
                  >
                      Giriş Yap
                  </button>
              </form>
          )}
        </div>

        <p className="text-center mt-20 text-stone-300 text-[9px] font-black uppercase tracking-[0.3em]">
          Handcrafted by Ev Coffee &bull; v2.2
        </p>
      </div>
    </div>
  );
};

export default Login;

import React, { useMemo, useState, useEffect } from 'react';
import { Order } from '../types';
import { SIZE_LABELS } from '../constants';

interface AdminDashboardProps {
  orders: Order[];
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onClearOrder: (id: string) => void;
  isServiceOnline: boolean;
  onToggleService: (status: boolean) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
    orders, 
    onUpdateStatus, 
    onClearOrder, 
    isServiceOnline, 
    onToggleService 
}) => {
  const [lastOrderCount, setLastOrderCount] = useState(orders.length);
  const [newOrderToast, setNewOrderToast] = useState<{ name: string; type: string } | null>(null);

  const pendingCount = useMemo(() => orders.filter(o => o.status !== 'COMPLETED').length, [orders]);
  const completedCount = useMemo(() => orders.filter(o => o.status === 'COMPLETED').length, [orders]);
  const sortedOrders = useMemo(() => [...orders].sort((a, b) => b.timestamp - a.timestamp), [orders]);

  useEffect(() => {
    if (orders.length > lastOrderCount) {
      const newestOrder = orders.reduce((prev, current) => (prev.timestamp > current.timestamp) ? prev : current);
      setNewOrderToast({ name: newestOrder.guestName, type: newestOrder.coffeeType });
      const timer = setTimeout(() => setNewOrderToast(null), 6000);
      return () => clearTimeout(timer);
    }
    setLastOrderCount(orders.length);
  }, [orders, lastOrderCount]);

  return (
    <div className="space-y-8 relative">
      {newOrderToast && (
        <div className="fixed top-24 right-6 z-[60] animate-bounce-in">
          <div className="bg-stone-900 text-white p-6 rounded-2xl shadow-2xl border border-stone-800 flex items-center gap-5 min-w-[340px]">
            <div className="w-14 h-14 bg-white/10 rounded-2xl flex items-center justify-center text-2xl shrink-0 backdrop-blur-sm">☕</div>
            <div>
              <div className="text-[10px] font-black text-stone-500 uppercase tracking-[0.2em] mb-1">Yeni Sipariş!</div>
              <div className="font-serif text-lg leading-tight">{newOrderToast.name} için bir {newOrderToast.type}</div>
            </div>
            <button onClick={() => setNewOrderToast(null)} className="ml-auto p-1 text-stone-600 hover:text-white transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
              </svg>
            </button>
          </div>
        </div>
      )}

      {/* Kontrol Paneli Üst Bar */}
      <div className="flex flex-col md:flex-row gap-6 justify-between items-center bg-white p-6 rounded-3xl shadow-sm border border-stone-100">
         <div className="flex-1">
             <h2 className="text-2xl font-serif text-stone-800">Servis Durumu</h2>
             <p className="text-stone-400 text-sm">Misafirler sipariş verebilsin mi?</p>
