import React, { useState, useEffect } from 'react';
import { UserRole, Order } from './types';
import Login from './components/Login';
import Layout from './components/Layout';
import GuestDashboard from './components/GuestDashboard';
import AdminDashboard from './components/AdminDashboard';
import { db, auth } from './services/firebase';
import { 
  ref, 
  onValue, 
  push, 
  update, 
  remove,
  set
} from 'firebase/database';
import { onAuthStateChanged, signOut } from 'firebase/auth';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.NONE);
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [dbError, setDbError] = useState<string | null>(null);
  const [permissionError, setPermissionError] = useState(false);
  const [isServiceOnline, setIsServiceOnline] = useState(true); // Varsayılan açık

  // Auth durumunu ve Oturum Süresini (2 Gün) dinle
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      if (user) {
        // Oturum süresi kontrolü (2 Gün = 48 saat)
        const loginTimeStr = localStorage.getItem('evCoffeeLoginTime');
        const storedRole = localStorage.getItem('evCoffeeRole');

        // Eğer yönetici ise ve süre dolmuşsa at
        if (storedRole === UserRole.ADMIN && loginTimeStr) {
          const loginTime = parseInt(loginTimeStr, 10);
          const twoDaysInMs = 48 * 60 * 60 * 1000;
          const now = Date.now();

          if (now - loginTime > twoDaysInMs) {
            // Süre dolmuş
            handleLogout();
            setLoading(false);
            return;
          }
        }

        if (storedRole === UserRole.ADMIN) {
          setRole(UserRole.ADMIN);
        } else {
          setRole(UserRole.GUEST);
        }
      } else {
        setRole(UserRole.NONE);
        localStorage.removeItem('evCoffeeRole');
        localStorage.removeItem('evCoffeeLoginTime');
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  // Firebase Realtime Database'den verileri ve sistem durumunu dinle
  useEffect(() => {
    if (role === UserRole.NONE) {
      setOrders([]);
      return;
    }

    // 1. Siparişleri Dinle
    const ordersRef = ref(db, 'orders');
    const unsubscribeOrders = onValue(ordersRef, (snapshot) => {
      setDbError(null); 
      setPermissionError(false);
      const data = snapshot.val();
      if (data) {
        const ordersArray = Object.entries(data).map(([key, value]) => {
          return {
            id: key,
            ...(value as Omit<Order, 'id'>)
          };
        });
        setOrders(ordersArray.sort((a, b) => b.timestamp - a.timestamp));
      } else {
        setOrders([]);
      }
    }, (error) => {
      console.error("Veri okuma hatası:", error);
      if (error.code === 'PERMISSION_DENIED' || error.message.includes('permission_denied')) {
        setPermissionError(true);
        setDbError("Erişim Reddedildi: Veritabanı kuralları (Rules) yapılandırılmamış.");
      } else {
        setDbError(`Bağlantı Hatası: ${error.message}. Lütfen services/firebase.ts dosyasındaki databaseURL ayarını kontrol edin.`);
      }
    });

    // 2. Sistem Durumunu (Servis Açık/Kapalı) Dinle
    const systemRef = ref(db, 'system/isOnline');
    const unsubscribeSystem = onValue(systemRef, (snapshot) => {
      const val = snapshot.val();
      // Eğer veritabanında kayıt yoksa varsayılan true kabul et
      setIsServiceOnline(val === null ? true : val);
    });

    return () => {
      unsubscribeOrders();
      unsubscribeSystem();
    };
  }, [role]);

  const handlePlaceOrder = async (orderData: Omit<Order, 'id' | 'timestamp' | 'status'>) => {
    try {
      if (!isServiceOnline) {
        throw new Error("Servis şu anda kapalıdır.");
      }

      const ordersRef = ref(db, 'orders');
      const newOrderRef = push(ordersRef);

      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error("Zaman Aşımı")), 10000)
      );

      const savePromise = set(newOrderRef, {
        ...orderData,
        timestamp: Date.now(),
        status: 'PENDING'
      });

      await Promise.race([savePromise, timeoutPromise]);

      return newOrderRef.key; 
    } catch (error: any) {
      console.error("Sipariş hatası:", error);

      let errorMessage = "Sipariş gönderilemedi.";
      if (error.code === 'PERMISSION_DENIED' || error.message.includes('permission_denied')) {
        setPermissionError(true);
        errorMessage = "Yetki Hatası: Veritabanı kuralları yazmaya izin vermiyor.";
      } else if (error.message === "Zaman Aşımı") {
        errorMessage = "Veritabanına ulaşılamadı. İnternet bağlantınızı kontrol edin.";
      } else {
        errorMessage += " " + error.message;
      }

      if (!permissionError && error.code !== 'PERMISSION_DENIED' && !error.message.includes('permission_denied')) {
          alert(errorMessage);
      }
      throw error;
    }
  };

  const handleUpdateStatus = async (id: string, status: Order['status']) => {
    try {
      const orderRef = ref(db, `orders/${id}`);
      await update(orderRef, { status });
    } catch (error: any) {
      console.error("Güncelleme hatası:", error);
      if (error.code === 'PERMISSION_DENIED' || error.message.includes('permission_denied')) {
         setPermissionError(true);
      } else {
         alert("Durum güncellenemedi: " + error.message);
      }
    }
  };

  const handleClearOrder = async (id: string) => {
    try {
      const orderRef = ref(db, `orders/${id}`);
      await remove(orderRef);
    } catch (error: any) {
      console.error("Silme hatası:", error);
      if (error.code === 'PERMISSION_DENIED' || error.message.includes('permission_denied')) {
         setPermissionError(true);
      }
    }
  };

  // Misafir kendi siparişini iptal ederken de aynı silme mantığını kullanır
  const handleGuestCancelOrder = async (id: string) => {
      await handleClearOrder(id);
  };

  const handleToggleService = async (newStatus: boolean) => {
    try {
      await set(ref(db, 'system/isOnline'), newStatus);
    } catch (error: any) {
      alert("Durum değiştirilemedi: " + error.message);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('evCoffeeRole');
    localStorage.removeItem('evCoffeeLoginTime');
    signOut(auth).catch(err => console.error("Çıkış hatası:", err));
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#fcfaf7]">
        <div className="animate-pulse text-stone-400 font-serif">Yükleniyor...</div>
      </div>
    );
  }

  // Permission Error Modal
  if (permissionError) {
    return (
      <div className="fixed inset-0 z-[100] bg-stone-900/90 backdrop-blur-sm flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 max-w-2xl w-full shadow-2xl border-4 border-red-100">
          <div className="flex items-start gap-6">
            <div className="w-16 h-16 bg-red-50 rounded-2xl flex items-center justify-center shrink-0">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
               </svg>
            </div>
            <div className="space-y-4">
              <h2 className="text-2xl font-serif text-stone-900">Veritabanı Kuralları Eksik</h2>
              <p className="text-stone-600">
                Uygulama veritabanına bağlandı ancak <strong>yazma/okuma izni alamadı</strong>. <br/>
                Bu hatayı düzeltmek için Firebase Konsolu'nda şu adımları izleyin:
              </p>

              <ol className="list-decimal list-inside text-sm text-stone-600 space-y-1 ml-1">
                <li>Firebase Konsolu &gt; <strong>Realtime Database</strong> sekmesine gidin.</li>
                <li>Yukarıdaki <strong>Rules (Kurallar)</strong> sekmesine tıklayın.</li>
                <li>Mevcut kodları silin ve aşağıdakini yapıştırın:</li>
              </ol>

              <div className="bg-stone-900 rounded-xl p-4 relative group text-left">
                <code className="text-green-400 font-mono text-sm whitespace-pre block">
{`{
  "rules": {
    ".read": "auth != null",
    ".write": "auth != null"
  }
}`}
                </code>
              </div>

              <div className="bg-orange-50 p-4 rounded-xl border border-orange-100">
                <p className="text-orange-800 text-xs font-bold">
                  İPUCU: "Publish" (Yayınla) butonuna basmayı unutmayın.
                </p>
              </div>

              <button 
                onClick={() => window.location.reload()}
                className="w-full py-4 bg-stone-800 hover:bg-stone-900 text-white rounded-xl font-bold transition-all mt-2"
              >
                Kuralları Güncelledim, Yeniden Dene
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (role === UserRole.NONE) {
    return <Login />;
  }

  return (
    <Layout role={role} onLogout={handleLogout}>
      {dbError && role === UserRole.ADMIN && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-2xl text-red-700 text-sm font-bold flex items-center gap-3">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
           {dbError}
        </div>
      )}

      {role === UserRole.GUEST ? (
        <GuestDashboard 
          orders={orders} 
          onPlaceOrder={handlePlaceOrder} 
          onCancelOrder={handleGuestCancelOrder}
          isServiceOnline={isServiceOnline}
        />
      ) : (
        <AdminDashboard 
          orders={orders} 
          onUpdateStatus={handleUpdateStatus} 
          onClearOrder={handleClearOrder}
          isServiceOnline={isServiceOnline}
          onToggleService={handleToggleService}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { COFFEE_OPTIONS, SIZES, SIZE_LABELS } from '../constants';
import { CoffeeType, CoffeeSize, Order, MilkLevel } from '../types';

interface GuestDashboardProps {
  orders: Order[];
  onPlaceOrder: (order: Omit<Order, 'id' | 'timestamp' | 'status'>) => Promise<string | null>;
  onCancelOrder: (orderId: string) => Promise<void>;
  isServiceOnline: boolean;
}

const GuestDashboard: React.FC<GuestDashboardProps> = ({ orders, onPlaceOrder, onCancelOrder, isServiceOnline }) => {
  const [name, setName] = useState('');
  const [selectedCoffee, setSelectedCoffee] = useState<CoffeeType | null>(null);
  const [size, setSize] = useState<CoffeeSize>(CoffeeSize.MEDIUM);
  const [percentage, setPercentage] = useState(50);
  const [milkLevel, setMilkLevel] = useState<MilkLevel>('Standart');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [trackedOrderId, setTrackedOrderId] = useState<string | null>(null);

  // Takip edilen siparişi bul
  const trackedOrder = useMemo(() => {
    if (!trackedOrderId) return null;
    return orders.find(o => o.id === trackedOrderId) || null;
  }, [orders, trackedOrderId]);

  // Seçilen kahve detayını bul
  const selectedCoffeeDetails = useMemo(() => {
    return COFFEE_OPTIONS.find(c => c.id === selectedCoffee);
  }, [selectedCoffee]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !selectedCoffee || isSubmitting) return;

    setIsSubmitting(true);
    try {
      const orderId = await onPlaceOrder({
        guestName: name,
        coffeeType: selectedCoffee,
        size,
        percentage,
        // Sadece sütlü kahveyse süt oranını gönder, değilse undefined
        milkLevel: selectedCoffeeDetails?.isMilky ? milkLevel : undefined
      });

      if (orderId) {
        setTrackedOrderId(orderId);
      }

      // Formu temizle ama isim kalsın
      setSelectedCoffee(null);
      setMilkLevel('Standart');
      setPercentage(50);

    } catch (error) {
      // Hata App.tsx'te handle ediliyor
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleNewOrder = () => {
    setTrackedOrderId(null);
    setSelectedCoffee(null);
  };

  const handleCancelClick = async () => {
    if (!trackedOrder) return;
    if (window.confirm('Siparişinizi iptal etmek istediğinize emin misiniz?')) {
      await onCancelOrder(trackedOrder.id);
      setTrackedOrderId(null);
    }
  };

  // 1. SERVİS KAPALI EKRANI
  if (!isServiceOnline && !trackedOrder) {
      return (
        <div className="max-w-2xl mx-auto py-16 animate-fade-in text-center px-6">
             <div className="w-24 h-24 bg-stone-200 rounded-full flex items-center justify-center mx-auto text-stone-400 mb-8">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
               </svg>
            </div>
            <h2 className="text-4xl font-serif text-stone-800 mb-4">Servisimiz Kapalıdır</h2>
            <p className="text-stone-500 text-lg">Şu anda kahve servisi yapılmamaktadır. <br/>Daha sonra tekrar bekleriz.</p>
        </div>
      );
  }

  // 2. DURUM EKRANI
  if (trackedOrder) {
    const isCompleted = trackedOrder.status === 'COMPLETED';
    const isPreparing = trackedOrder.status === 'PREPARING';
    const isPending = trackedOrder.status === 'PENDING';

    return (
      <div className="max-w-2xl mx-auto py-10 animate-fade-in">
        <div className="bg-white rounded-[2.5rem] shadow-xl border border-stone-100 overflow-hidden relative">

          <div className={`p-10 text-center transition-colors duration-500 ${
            isCompleted ? 'bg-stone-800 text-white' : 
            isPreparing ? 'bg-orange-50 text-stone-800' : 
            'bg-stone-50 text-stone-600'
          }`}>
            <div className="inline-flex items-center justify-center w-24 h-24 rounded-full bg-white shadow-lg mb-6 text-4xl">
              {isCompleted ? '☕' : isPreparing ? '🔥' : '⏳'}
            </div>
            <h2 className="text-3xl font-serif font-bold mb-2">
              {isCompleted ? 'Afiyet Olsun!' : 
               isPreparing ? 'Hazırlanıyor...' : 
               'Sıraya Alındı'}
            </h2>
            <p className="text-sm font-medium opacity-80 uppercase tracking-widest">
              {isCompleted ? 'Kahveniz servise hazır.' : 
               isPreparing ? 'Barista kahvenizi hazırlıyor.' : 
               'Siparişiniz baristaya iletildi.'}
            </p>
          </div>

          <div className="px-10 py-8">
            <div className="flex justify-between text-[10px] font-black uppercase tracking-[0.2em] text-stone-300 mb-4">
              <span className={isPending || isPreparing || isCompleted ? 'text-stone-800' : ''}>Sırada</span>
              <span className={isPreparing || isCompleted ? 'text-stone-800' : ''}>Hazırlanıyor</span>
              <span className={isCompleted ? 'text-stone-800' : ''}>Hazır</span>
            </div>
            <div className="h-3 bg-stone-100 rounded-full overflow-hidden">
              <div 
                className="h-full bg-stone-800 transition-all duration-1000 ease-out"
                style={{ 
                  width: isCompleted ? '100%' : isPreparing ? '66%' : '33%' 
                }}
              />
            </div>
          </div>

          <div className="px-10 pb-10">
            <div className="bg-stone-50 rounded-2xl p-6 border border-stone-100 flex items-center gap-4">
              <div className="w-16 h-16 rounded-xl bg-white flex items-center justify-center text-2xl shadow-sm">
                ☕
              </div>
              <div className="flex-1">
                <div className="text-lg font-serif font-bold text-stone-800">{trackedOrder.coffeeType}</div>
                <div className="text-xs text-stone-500 font-medium">
                  {SIZE_LABELS[trackedOrder.size]} • %{trackedOrder.percentage} Sertlik
                  {trackedOrder.milkLevel && (
                    <span className="block mt-1 text-stone-400 font-bold uppercase text-[10px]">
                      {trackedOrder.milkLevel}
                    </span>
                  )}
                </div>
              </div>
            </div>

            <div className="space-y-3 mt-8">
                {/* Yeni Sipariş Verme Butonu - Her Zaman Aktif (Servis Açıksa) */}
                {isServiceOnline && (
                  <button 
                    onClick={handleNewOrder}
                    className="w-full py-5 bg-stone-800 text-white rounded-2xl font-bold uppercase tracking-widest hover:bg-stone-900 transition-all shadow-lg active:scale-[0.98] flex items-center justify-center gap-2"
                  >
                    <span>{isCompleted ? 'Yeni Sipariş Ver' : 'Başka Bir Tane Daha Ekle'}</span>
                    {!isCompleted && <span className="text-lg leading-none">+</span>}
                  </button>
                )}

                {/* İptal Butonu - Sadece PENDING Durumunda */}
                {isPending && (
                   <button 
                     onClick={handleCancelClick}
                     className="w-full py-4 text-red-500 hover:bg-red-50 rounded-2xl font-bold uppercase tracking-widest text-xs transition-colors"
                   >
                     Siparişi İptal Et
                   </button>
                )}
            </div>

            {isCompleted && !isServiceOnline && (
                 <p className="mt-8 text-center text-red-500 font-bold text-sm">
                     Servis kapandığı için yeni sipariş verilemez.
                 </p>
            )}

            {!isCompleted && (
               <p className="text-center mt-6 text-xs text-stone-400 italic">
                 Ekran otomatik güncellenecektir...
               </p>
            )}
          </div>
        </div>
      </div>
    );
  }

  // 3. SİPARİŞ FORMU
  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-10 text-center">
        <h2 className="text-3xl font-serif text-stone-800 mb-2">Kahve Siparişi</h2>
        <p className="text-stone-400 italic">Evinizdeki konforla, size özel hazırlanan lezzetler.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
          <h3 className="text-xl font-serif text-stone-800 mb-6 flex items-center gap-3">
            <span className="w-8 h-8 rounded-full bg-stone-100 text-stone-800 flex items-center justify-center text-sm font-bold">1</span>
            Kimin İçin?
          </h3>
          <input 
            type="text" 
            required
            placeholder="İsim soyisim giriniz"
            className="w-full px-6 py-4 text-lg rounded-2xl border border-stone-200 focus:ring-2 focus:ring-stone-800 focus:border-transparent outline-none transition-all"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
        </section>

        <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
          <h3 className="text-xl font-serif text-stone-800 mb-6 flex items-center gap-3">
            <span className="w-8 h-8 rounded-full bg-stone-100 text-stone-800 flex items-center justify-center text-sm font-bold">2</span>
            Kahvenizi Seçin
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {COFFEE_OPTIONS.map((coffee) => (
              <div 
                key={coffee.id}
                onClick={() => !coffee.isComingSoon && setSelectedCoffee(coffee.id)}
                className={`group relative rounded-3xl overflow-hidden border-2 transition-all duration-300 ${
                  coffee.isComingSoon ? 'cursor-not-allowed opacity-90' : 'cursor-pointer'
                } ${
                  selectedCoffee === coffee.id ? 'border-stone-800 ring-8 ring-stone-50 scale-[1.02]' : 'border-stone-50 hover:border-stone-200'
                }`}
              >
                <div className="h-48 overflow-hidden relative">
                  <img 
                    src={coffee.image} 
                    alt={coffee.name} 
                    className={`w-full h-full object-cover transition-transform duration-700 ${coffee.isComingSoon ? 'grayscale-[0.5]' : 'group-hover:scale-110'}`} 
                  />

                  {/* Yakında Gelecek Overlay */}
                  {coffee.isComingSoon && (
                    <div className="absolute inset-0 bg-stone-900/60 z-10 flex items-center justify-center backdrop-blur-[2px]">
                      <span className="bg-white/95 text-stone-900 px-4 py-2 font-black text-xs uppercase tracking-widest rounded-lg transform -rotate-6 shadow-xl border border-stone-200">
                        Yakında Gelecek
                      </span>
                    </div>
                  )}
                </div>
                <div className="p-5 bg-white relative">
                  <h4 className={`font-bold text-lg ${coffee.isComingSoon ? 'text-stone-400' : 'text-stone-800'}`}>{coffee.name}</h4>
                  <p className="text-xs text-stone-400 mt-1 leading-relaxed">{coffee.description}</p>
                </div>
                {selectedCoffee === coffee.id && (
                  <div className="absolute top-4 right-4 bg-stone-800 text-white rounded-full p-2 shadow-lg z-20">
