                <button 
                    onClick={() => setViewMode('FORM')}
                    className="w-full py-4 bg-stone-800 text-white rounded-2xl font-bold uppercase tracking-widest hover:bg-stone-900 transition-all shadow-xl active:scale-[0.98] flex items-center justify-center gap-3 border border-stone-700"
                >
                    <span className="text-2xl leading-none font-light">+</span>
                    <span>Başka Bir Kahve Ekle</span>
                </button>
            </div>
        )}
      </div>
    );
  }

  // --- RENDER: FORM VIEW (Sipariş Ekranı) ---

  // Eğer servis kapalıysa ve form modundaysak (ve listede gösterilecek sipariş yoksa)
  if (!isServiceOnline && viewMode === 'FORM') {
