import React, { useState } from 'react';
import { auth } from '../services/firebase';
import { signInAnonymously } from 'firebase/auth';
import { UserRole } from '../types';

const Login: React.FC = () => {
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [password, setPassword] = useState('');

  const handleLogin = async (targetRole: UserRole) => {
    setLoading(true);
    setError(null);

    // Role ve Zamanı Kaydet
    localStorage.setItem('evCoffeeRole', targetRole);
    // Yönetici ise giriş zamanını kaydet (2 gün kontrolü için)
    if (targetRole === UserRole.ADMIN) {
        localStorage.setItem('evCoffeeLoginTime', Date.now().toString());
    }

    try {
      await signInAnonymously(auth);
    } catch (err: any) {
      console.error("Giriş hatası:", err);
      // Hata durumunda storage'ı temizle
      localStorage.removeItem('evCoffeeRole');
      localStorage.removeItem('evCoffeeLoginTime');

      if (err.code === 'auth/configuration-not-found') {
        setError("Firebase Konsolunda 'Anonymous' oturum açma yöntemi etkinleştirilmemiş.");
      } else {
        setError("Giriş yapılamadı: " + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleAdminClick = () => {
      setShowPassword(true);
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (password === '2908') {
          handleLogin(UserRole.ADMIN);
      } else {
          setError("Hatalı Şifre");
          setPassword('');
      }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 md:p-6 bg-[#fcfaf7]">
      <div className="max-w-md w-full">
        <div className="text-center mb-10 md:mb-16">
          <div className="w-16 h-16 md:w-20 md:h-20 bg-stone-800 rounded-2xl flex items-center justify-center text-white font-bold text-3xl md:text-4xl mx-auto shadow-2xl mb-6 md:mb-8 italic">E</div>
          <h1 className="text-4xl md:text-5xl font-serif text-stone-800 mb-3 tracking-tighter">Ev Coffee</h1>
          <p className="text-stone-400 font-medium italic text-sm">Evinizdeki kahve ritüeli.</p>
        </div>

        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-xs font-bold">
            {error}
          </div>
        )}

        <div className="space-y-4 md:space-y-5">
          {!showPassword ? (
              <>
                {/* Misafir Girişi Butonu */}
                <button 
                    onClick={() => handleLogin(UserRole.GUEST)}
                    disabled={loading}
                    className="w-full p-6 md:p-8 bg-white border border-stone-100 rounded-3xl shadow-sm hover:shadow-2xl hover:translate-y-[-4px] transition-all text-left group relative overflow-hidden disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    <div className="relative z-10 flex items-center justify-between gap-4">
                    <div>
                        <h2 className="text-xl md:text-2xl font-serif text-stone-800">Misafir Girişi</h2>
                        <p className="text-[10px] md:text-xs text-stone-400 mt-1 md:mt-2 font-bold uppercase tracking-widest">
                        {loading ? 'Giriş Yapılıyor...' : 'Kahveni Sipariş Et'}
                        </p>
                    </div>
                    <div className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-stone-50 flex items-center justify-center text-stone-800 group-hover:bg-stone-800 group-hover:text-white transition-all duration-500 shrink-0">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
                        </svg>
                    </div>
                    </div>
                </button>

                {/* Barista Girişi Butonu (Şifre Ekranını Açar) */}
                <button 
                    onClick={handleAdminClick}
                    disabled={loading}
                    className="w-full p-6 md:p-8 bg-stone-800 border border-stone-700 rounded-3xl shadow-lg hover:shadow-2xl hover:translate-y-[-4px] transition-all text-left group text-white disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    <div className="flex items-center justify-between gap-4">
                    <div>
                        <h2 className="text-xl md:text-2xl font-serif">Barista Paneli</h2>
                        <p className="text-[10px] md:text-xs text-stone-500 mt-1 md:mt-2 font-bold uppercase tracking-widest">
                        {loading ? 'Giriş Yapılıyor...' : 'Yönetici Girişi'}
                        </p>
                    </div>
                    <div className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-stone-700 flex items-center justify-center text-stone-400 group-hover:bg-white group-hover:text-stone-800 transition-all duration-500 shrink-0">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                        </svg>
                    </div>
                    </div>
                </button>
            </>
          ) : (
              <form onSubmit={handlePasswordSubmit} className="bg-white p-6 md:p-8 rounded-3xl shadow-xl border border-stone-100 animate-fade-in">
                  <div className="flex justify-between items-center mb-6">
                    <h2 className="text-lg md:text-xl font-serif text-stone-800">Şifre Giriniz</h2>
                    <button type="button" onClick={() => setShowPassword(false)} className="text-stone-400 hover:text-stone-800">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                        </svg>
                    </button>
                  </div>
                  <input 
                    type="password" 
                    autoFocus
                    placeholder="****"
                    className="w-full text-center text-3xl tracking-[1em] py-4 border-b-2 border-stone-200 focus:border-stone-800 outline-none mb-6 font-serif"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    maxLength={4}
                  />
                  <button 
                    type="submit" 
                    className="w-full py-4 bg-stone-800 text-white rounded-xl font-bold uppercase tracking-widest hover:bg-stone-900 transition-all"
                  >
                      Giriş Yap
                  </button>
              </form>
          )}
        </div>

        <p className="text-center mt-12 md:mt-20 text-stone-300 text-[9px] font-black uppercase tracking-[0.3em]">
          Handcrafted by Ev Coffee &bull; v2.2
        </p>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useMemo, useEffect } from 'react';
import { COFFEE_OPTIONS, SIZES, SIZE_LABELS } from '../constants';
import { CoffeeType, CoffeeSize, Order, MilkLevel } from '../types';

interface GuestDashboardProps {
  orders: Order[];
  onPlaceOrder: (order: Omit<Order, 'id' | 'timestamp' | 'status'>) => Promise<string | null>;
  isServiceOnline: boolean;
}

type ViewMode = 'FORM' | 'STATUS';

const GuestDashboard: React.FC<GuestDashboardProps> = ({ orders, onPlaceOrder, isServiceOnline }) => {
  // LocalStorage'dan sipariş geçmişini al veya boş başlat
  const [myOrderIds, setMyOrderIds] = useState<string[]>(() => {
    const saved = localStorage.getItem('evCoffee_myOrders');
    return saved ? JSON.parse(saved) : [];
  });

  // Aktif görünüm modu (Eğer sipariş varsa direkt listeyi göster)
  const [viewMode, setViewMode] = useState<ViewMode>(() => {
    const saved = localStorage.getItem('evCoffee_myOrders');
    const ids = saved ? JSON.parse(saved) : [];
    return ids.length > 0 ? 'STATUS' : 'FORM';
  });

  const [name, setName] = useState(() => localStorage.getItem('evCoffee_guestName') || '');
  const [selectedCoffee, setSelectedCoffee] = useState<CoffeeType | null>(null);
  const [size, setSize] = useState<CoffeeSize>(CoffeeSize.MEDIUM);
  const [percentage, setPercentage] = useState(50);
  const [milkLevel, setMilkLevel] = useState<MilkLevel>('Standart');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // myOrderIds değiştiğinde LocalStorage'ı güncelle
  useEffect(() => {
    localStorage.setItem('evCoffee_myOrders', JSON.stringify(myOrderIds));
  }, [myOrderIds]);

  // İsim değiştiğinde kaydet (kolaylık olsun diye)
  useEffect(() => {
    localStorage.setItem('evCoffee_guestName', name);
  }, [name]);

  // Global sipariş listesinden, bu kullanıcının siparişlerini filtrele
  // Sipariş veritabanından silindiyse (admin sildiyse veya iptal edildiyse) listeden düşer.
  const myActiveOrders = useMemo(() => {
    return orders
      .filter(o => myOrderIds.includes(o.id))
      .sort((a, b) => b.timestamp - a.timestamp); // En yeni en üstte
  }, [orders, myOrderIds]);

  // Eğer tüm siparişler silindiyse/bittiyse ve listede duruyorsak, forma dönebiliriz (Opsiyonel, şimdilik manuel bırakıyoruz)

  const selectedCoffeeDetails = useMemo(() => {
    return COFFEE_OPTIONS.find(c => c.id === selectedCoffee);
  }, [selectedCoffee]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !selectedCoffee || isSubmitting) return;

    setIsSubmitting(true);
    try {
      const orderId = await onPlaceOrder({
        guestName: name,
        coffeeType: selectedCoffee,
        size,
        percentage,
        milkLevel: selectedCoffeeDetails?.isMilky ? milkLevel : undefined
      });

      if (orderId) {
        setMyOrderIds(prev => [orderId, ...prev]);
        setViewMode('STATUS'); // Sipariş verilince durum ekranına at

        // Formu kısmen temizle, isim kalsın
        setSelectedCoffee(null);
        setMilkLevel('Standart');
        setPercentage(50);
      }

    } catch (error) {
      // Hata App.tsx'te handle ediliyor
    } finally {
      setIsSubmitting(false);
    }
  };

  // --- RENDER: STATUS VIEW (Sipariş Listesi) ---
  if (viewMode === 'STATUS' && (myActiveOrders.length > 0 || !isServiceOnline)) {
    return (
      <div className="max-w-3xl mx-auto py-2 md:py-6 animate-fade-in pb-24">

        {/* Başlık Alanı */}
        <div className="text-center mb-6 md:mb-8">
          <h2 className="text-2xl md:text-3xl font-serif text-stone-800">Siparişleriniz</h2>
          <p className="text-stone-400 italic text-sm mt-1">Afiyet olsun, {name || 'Misafir'}!</p>
        </div>

        {/* Sipariş Listesi */}
        <div className="space-y-4 md:space-y-6">
            {myActiveOrders.map((order) => {
                const isCompleted = order.status === 'COMPLETED';
                const isPreparing = order.status === 'PREPARING';
                const isPending = order.status === 'PENDING';

                return (
                    <div key={order.id} className="bg-white rounded-[1.5rem] md:rounded-[2rem] shadow-lg border border-stone-100 overflow-hidden relative transition-all hover:shadow-xl">
                        {/* Durum Göstergesi (Üst Bant) */}
                        <div className={`px-4 md:px-6 py-3 flex items-center justify-between ${
                            isCompleted ? 'bg-stone-800 text-white' : 
                            isPreparing ? 'bg-orange-50 text-orange-800 border-b border-orange-100' : 
                            'bg-stone-50 text-stone-500 border-b border-stone-100'
                        }`}>
                            <div className="flex items-center gap-2 text-[10px] md:text-xs font-black uppercase tracking-widest">
                                {isCompleted ? (
                                    <><span className="text-lg md:text-xl">☕</span> Hazır</>
                                ) : isPreparing ? (
                                    <><span className="text-lg md:text-xl animate-pulse">🔥</span> Hazırlanıyor</>
                                ) : (
                                    <><span className="text-lg md:text-xl">⏳</span> Sırada</>
                                )}
                            </div>
                            <div className="text-[10px] font-mono opacity-60">
                                {new Date(order.timestamp).toLocaleTimeString('tr-TR', { hour: '2-digit', minute: '2-digit' })}
                            </div>
                        </div>

                        {/* İçerik */}
                        <div className="p-4 md:p-6">
                            <div className="flex items-start justify-between gap-4">
                                <div>
                                    <h3 className="text-lg md:text-xl font-serif font-bold text-stone-800">{order.coffeeType}</h3>
                                    <p className="text-[10px] md:text-xs text-stone-400 font-bold uppercase tracking-wide mt-1">
                                        {SIZE_LABELS[order.size]} 
                                        {order.milkLevel && <span className="mx-1">• {order.milkLevel}</span>}
                                        <span className="mx-1">• %{order.percentage} Sertlik</span>
                                    </p>
                                </div>
                            </div>

                            {/* Progress Bar */}
                            <div className="mt-4 md:mt-6">
                                <div className="flex justify-between text-[8px] font-black uppercase tracking-[0.2em] text-stone-300 mb-2">
                                    <span className={isPending || isPreparing || isCompleted ? 'text-stone-800' : ''}>Sırada</span>
                                    <span className={isPreparing || isCompleted ? 'text-stone-800' : ''}>Hazırlanıyor</span>
                                    <span className={isCompleted ? 'text-stone-800' : ''}>Teslim</span>
                                </div>
                                <div className="h-1.5 md:h-2 bg-stone-100 rounded-full overflow-hidden">
                                    <div 
                                        className="h-full bg-stone-800 transition-all duration-1000 ease-out"
                                        style={{ width: isCompleted ? '100%' : isPreparing ? '60%' : '20%' }}
                                    />
                                </div>
                            </div>
                        </div>
                    </div>
                );
            })}
        </div>

        {/* Servis Kapalı ve Sipariş Yoksa */}
        {!isServiceOnline && myActiveOrders.length === 0 && (
            <div className="text-center py-12">
                 <h2 className="text-2xl font-serif text-stone-800 mb-2">Servis Kapalı</h2>
                 <p className="text-stone-500">Şu anda yeni sipariş alınmamaktadır.</p>
            </div>
        )}

        {/* Yeni Sipariş Butonu */}
        {isServiceOnline && (
            <div className="mt-6 md:mt-8 sticky bottom-4 md:bottom-6 z-10 px-2 md:px-0">
                <button 
                    onClick={() => setViewMode('FORM')}
                    className="w-full py-3 md:py-4 bg-stone-800 text-white rounded-xl md:rounded-2xl font-bold uppercase tracking-widest hover:bg-stone-900 transition-all shadow-xl active:scale-[0.98] flex items-center justify-center gap-3 border border-stone-700 text-sm md:text-base"
                >
                    <span className="text-xl md:text-2xl leading-none font-light">+</span>
                    <span>Başka Bir Kahve Ekle</span>
                </button>
            </div>
        )}
      </div>
    );
  }

  // --- RENDER: FORM VIEW (Sipariş Ekranı) ---

  // Eğer servis kapalıysa ve form modundaysak (ve listede gösterilecek sipariş yoksa)
  if (!isServiceOnline && viewMode === 'FORM') {
    return (
        <div className="max-w-2xl mx-auto py-12 md:py-16 animate-fade-in text-center px-6">
             <div className="w-20 h-20 md:w-24 md:h-24 bg-stone-200 rounded-full flex items-center justify-center mx-auto text-stone-400 mb-6 md:mb-8">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 md:h-10 md:w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
               </svg>
            </div>
            <h2 className="text-3xl md:text-4xl font-serif text-stone-800 mb-4">Servisimiz Kapalıdır</h2>
            <p className="text-stone-500 text-base md:text-lg">Şu anda kahve servisi yapılmamaktadır. <br/>Daha sonra tekrar bekleriz.</p>
            {myActiveOrders.length > 0 && (
                <button 
                    onClick={() => setViewMode('STATUS')}
                    className="mt-8 text-stone-800 font-bold underline decoration-2 underline-offset-4"
                >
                    Mevcut Siparişlerimi Göster
                </button>
            )}
        </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto pb-20">

      {/* Üst Navigation (Eğer aktif sipariş varsa geri dönme tuşu) */}
      {myActiveOrders.length > 0 && (
          <button 
            onClick={() => setViewMode('STATUS')}
            className="mb-4 md:mb-6 flex items-center gap-2 text-stone-500 hover:text-stone-800 transition-colors text-[10px] md:text-xs font-bold uppercase tracking-widest"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 md:h-4 md:w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
            Siparişlerime Dön
          </button>
      )}

      <div className="mb-6 md:mb-10 text-center">
        <h2 className="text-2xl md:text-3xl font-serif text-stone-800 mb-2">Kahve Siparişi</h2>
        <p className="text-stone-400 italic text-sm md:text-base">Evinizdeki konforla, size özel hazırlanan lezzetler.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4 md:space-y-8">
        <section className="bg-white p-5 md:p-8 rounded-[1.5rem] md:rounded-3xl shadow-sm border border-stone-100">
          <h3 className="text-lg md:text-xl font-serif text-stone-800 mb-4 md:mb-6 flex items-center gap-3">
            <span className="w-6 h-6 md:w-8 md:h-8 rounded-full bg-stone-100 text-stone-800 flex items-center justify-center text-xs md:text-sm font-bold">1</span>
            Kimin İçin?
          </h3>
          <input 
            type="text" 
            required
            placeholder="İsim soyisim giriniz"
            className="w-full px-5 py-3 md:px-6 md:py-4 text-base md:text-lg rounded-2xl border border-stone-200 focus:ring-2 focus:ring-stone-800 focus:border-transparent outline-none transition-all"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
        </section>

        <section className="bg-white p-5 md:p-8 rounded-[1.5rem] md:rounded-3xl shadow-sm border border-stone-100">
          <h3 className="text-lg md:text-xl font-serif text-stone-800 mb-4 md:mb-6 flex items-center gap-3">
            <span className="w-6 h-6 md:w-8 md:h-8 rounded-full bg-stone-100 text-stone-800 flex items-center justify-center text-xs md:text-sm font-bold">2</span>
            Kahvenizi Seçin
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
            {COFFEE_OPTIONS.map((coffee) => (
              <div 
                key={coffee.id}
                onClick={() => !coffee.isComingSoon && setSelectedCoffee(coffee.id)}
                className={`group relative rounded-2xl md:rounded-3xl overflow-hidden border-2 transition-all duration-300 ${
                  coffee.isComingSoon ? 'cursor-not-allowed opacity-90' : 'cursor-pointer'
                } ${
                  selectedCoffee === coffee.id ? 'border-stone-800 ring-4 md:ring-8 ring-stone-50 scale-[1.02]' : 'border-stone-50 hover:border-stone-200'
                }`}
              >
